import hashlib
import json
import os

class 投票系统:
    def __init__(self):
        self.选举结果 = {}
        self.哈希值 = ""

    def 投票(self, 候选人):
        if 候选人 not in self.选举结果:
            self.选举结果[候选人] = 0
        self.选举结果[候选人] += 1
        self.更新哈希值()

    def 更新哈希值(self):
        votes_json = json.dumps(self.选举结果)
        self.哈希值 = hashlib.sha256(votes_json.encode()).hexdigest()

    def 查看结果(self):
        return self.选举结果

    def 查看哈希值(self):
        return self.哈希值

    def 验证结果(self, 提供的哈希值):
        return self.哈希值 == 提供的哈希值

